575	\section{Combined affine-corner $\Module\,k$-finite consumer (iter-042)}
576	\label{sec:module_finite_HModule_prime_of_affine_iter042}
577	
578	Iter-040 packaged the H${}^{>0}$ side of the affine-corner input as a class with consumer (Theorems~\ref{thm:Scheme_IsAffineHModuleVanishing}--\ref{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing}); iter-041 packaged the parallel H${}^0$ side (Theorems~\ref{thm:Scheme_IsAffineHModuleHomFinite}--\ref{thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite}). Each consumer covers one degree side: the H${}^0$ consumer requires $i = 0$, the H${}^{>0}$ consumer requires $0 < i$. At every downstream call site (in particular, the iter-029 LES finite-length transport queued for iter-044+), the user must select between the two by case-split on $i$. Iter-042 folds both consumers into a single uniform statement covering all $i \ge 0$ under both class hypotheses, so the LES can chain through every degree without per-position case-splits.
579	
580	\begin{theorem}\leanok
581	[Combined affine-corner $\Module\,k$-finite consumer]
582	  \label{thm:Scheme_module_finite_HModule_prime_of_affine}
583	  \lean{AlgebraicGeometry.Scheme.module_finite_HModule'_of_affine}
584	  \uses{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing, thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite}
585	  Let $k$ be a field, $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$, and $F$ a sheaf of $\ModuleCat\,k$ on $\Opens\,(C.\mathtt{left}.\toTopCat)$. Assume \lstinline{IsAffineHModuleVanishing k C F} and \lstinline{IsAffineHModuleHomFinite k C F}. For any affine open $U$ of $C.\mathtt{left}$ and any $i \ge 0$, the cohomology group $\HModulePrime\,k\,F\,i\,U$ is $\Module.\mathrm{Finite}$ over $k$.
586	\end{theorem}
587	
588	\begin{proof}
589	  \uses{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing, thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite}
590	  \leanok
591	  Case-split on \lstinline{Nat.eq_zero_or_pos i}. If $i = 0$, the iter-041 consumer (Theorem~\ref{thm:Scheme_module_finite_HModule_prime_zero_of_isAffineHModuleHomFinite}) under \lstinline{IsAffineHModuleHomFinite k C F} produces $\Module.\mathrm{Finite}\,k\,(\HModulePrime\,k\,F\,0\,U)$. If $0 < i$, the iter-040 consumer (Theorem~\ref{thm:Scheme_module_finite_HModule_prime_of_isAffineHModuleVanishing}) under \lstinline{IsAffineHModuleVanishing k C F} produces $\Module.\mathrm{Finite}\,k\,(\HModulePrime\,k\,F\,i\,U)$. Combined body: \lstinline{by rcases Nat.eq_zero_or_pos i with rfl | hi; \cdot exact module_finite_HModule'_zero_of_isAffineHModuleHomFinite k C F hU; \cdot exact module_finite_HModule'_of_isAffineHModuleVanishing k C F hU i hi}.
592	\end{proof}
