598	  \uses{thm:Scheme_module_finite_HModule_prime_of_affine}
599	  Direct curve specialisation of Theorem~\ref{thm:Scheme_module_finite_HModule_prime_of_affine} to $F := \toModuleKSheaf\,C$ for $C : \Over\,(\Spec\,(\CommRingCat.\mathrm{of}\,k))$. Under \lstinline{IsAffineHModuleVanishing k C (toModuleKSheaf C)} and \lstinline{IsAffineHModuleHomFinite k C (toModuleKSheaf C)}, for any affine open $U$ of $C.\mathtt{left}$ and any $i \ge 0$, the cohomology group $\HModulePrime\,k\,(\toModuleKSheaf\,C)\,i\,U$ is $\Module.\mathrm{Finite}$ over $k$.
600	\end{theorem}
601	
602	\begin{proof}
603	  \uses{thm:Scheme_module_finite_HModule_prime_of_affine}
604	  \leanok
605	  One-line dot-notation wrapper: \lstinline{Scheme.module_finite_HModule'_of_affine k C (Scheme.toModuleKSheaf C) hU i}, mirroring the iter-030 / iter-035 / iter-036 / iter-037 / iter-039 \texttt{\_curve} patterns.
606	\end{proof}
